/*
Finds minimum of function f(i) where is is of type size_t, f(i) is of type
double, i is in range start-end (excluding end).
Outputs the minimum value in *smallest and returns the index of this value.

NOTE (CBMC): FindMinimum takes a function-pointer parameter (FindMinimumFun f).
Under the fixed scoring harness it is UNVERIFIABLE: CBMC's function-pointer
removal resolves f to SplitCost (the only double(size_t,void*) function), whose
call tree reaches the self-recursive BoundaryPM, so enforce-contract inlining
aborts at goto-instrument with a numeric exception ("Recursive call to
'BoundaryPM' during inlining"). The unmutated original crashes identically with
or without a contract, so all 52 mutants are uncheckable (kill score 0). The
spec below is the strongest SOUND contract; it cannot be verified or scored.
*/
static size_t FindMinimum(FindMinimumFun f, void *context,
                          size_t start, size_t end, double *smallest)
__CPROVER_requires(f != NULL)
__CPROVER_requires(start < end)
__CPROVER_requires(__CPROVER_is_fresh(smallest, sizeof(*smallest)))
__CPROVER_assigns(*smallest)
__CPROVER_ensures(__CPROVER_return_value >= __CPROVER_old(start) &&
                  __CPROVER_return_value < __CPROVER_old(end))
{
    if (end - start < 1024)
    {
        double best = ZOPFLI_LARGE_FLOAT;
        size_t result = start;
        size_t i;
        for (i = start; i < end; i++)
        {
            double v = f(i, context);
            if (v < best)
            {
                best = v;
                result = i;
            }
        }
        *smallest = best;
        return result;
    }
    else
    {
        /* Try to find minimum faster by recursively checking multiple points. */
#define NUM 9 /* Good value: 9. */
        size_t i;
        size_t p[NUM];
        double vp[NUM];
        size_t besti;
        double best;
        double lastbest = ZOPFLI_LARGE_FLOAT;
        size_t pos = start;

        for (;;)
        {
            if (end - start <= NUM)
                break;

            for (i = 0; i < NUM; i++)
            {
                p[i] = start + (i + 1) * ((end - start) / (NUM + 1));
                vp[i] = f(p[i], context);
            }
            besti = 0;
            best = vp[0];
            for (i = 1; i < NUM; i++)
            {
                if (vp[i] < best)
                {
                    best = vp[i];
                    besti = i;
                }
            }
            if (best > lastbest)
                break;

            start = besti == 0 ? start : p[besti - 1];
            end = besti == NUM - 1 ? end : p[besti + 1];

            pos = p[besti];
            lastbest = best;
        }
        *smallest = lastbest;
        return pos;
#undef NUM
    }
}

